import type Color from "../../Color.js";
import type { JSONSupport } from "../../core/JSONSupport.js";
import type { ColorLike } from "../../Color.js";

export interface HeatmapColorStopProperties extends Partial<Pick<HeatmapColorStop, "ratio">> {
  /** The color to shade a given pixel based on its calculated density [ratio](https://developers.arcgis.com/javascript/latest/references/core/renderers/support/HeatmapColorStop/#ratio). */
  color?: ColorLike;
}

/**
 * This class is used to define an array of objects describing the [HeatmapRenderer](https://developers.arcgis.com/javascript/latest/references/core/renderers/HeatmapRenderer/)'s color ramp
 * and associated density value ratios. See [HeatmapRenderer](https://developers.arcgis.com/javascript/latest/references/core/renderers/HeatmapRenderer/) for examples of how this is used.
 *
 * @since 4.8
 * @see [HeatmapRenderer](https://developers.arcgis.com/javascript/latest/references/core/renderers/HeatmapRenderer/)
 */
export default class HeatmapColorStop extends JSONSupport {
  constructor(properties?: HeatmapColorStopProperties);
  /** The color to shade a given pixel based on its calculated density [ratio](https://developers.arcgis.com/javascript/latest/references/core/renderers/support/HeatmapColorStop/#ratio). */
  get color(): Color;
  set color(value: ColorLike);
  /**
   * The ratio of a pixel's density value to the [HeatmapRenderer.maxDensity](https://developers.arcgis.com/javascript/latest/references/core/renderers/HeatmapRenderer/#maxDensity) of the renderer.
   * The ratio of each pixel is matched to the corresponding [color](https://developers.arcgis.com/javascript/latest/references/core/renderers/support/HeatmapColorStop/#color).
   */
  accessor ratio: number;
  /**
   * Creates a deep clone of the color stop.
   *
   * @returns A deep clone of the object that
   * invoked this method.
   */
  clone(): HeatmapColorStop;
}